    w[1][2] = 2; w[2][1] = 2;
    w[1][3] = 1; w[3][1] = 1;
    w[2][3] = 5; w[3][2] = 5;
    w[3][4] = 3; w[4][3] = 3;

    loop iter in 0..n {
        let u: Int = -1;
        let minVal: Int = INF;

        loop v in 0..n {
            if !visited[v] && dist[v] < minVal {
                minVal = dist[v];
                u = v;
